"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[23394],{33591(e,r,a){a.r(r),a.d(r,{assets:()=>o,contentTitle:()=>n,default:()=>l,frontMatter:()=>c,metadata:()=>s,toc:()=>h});const s=JSON.parse('{"id":"UserGuide/C19_Measurements/S12_Circle_markersfundamental_and_advanced_characteristics","title":"Circle markers: basic and advanced characteristics that should or can be specified","description":"A circle marker is simply a marker with a closed circular edge. Therefore, edge marker characteristics, as discussed previously in this chapter, generally apply to circle marker characteristics. To establish a circle marker, Aurora Imaging Library finds and extracts subedges using rectangular subregions of a ring search region and applies a circular fit to the subedges. The illustration below shows different possible circles, and how Aurora Imaging Library extracts and fits the subedges according to the ring search region. Note that, although circle markers are closed, the edges that Aurora Imaging Library uses to create them might not be closed; that is, Aurora Imaging Library can establish a circle marker even if part of it is missing. This is due to the fact that only three valid subedges are required to identify a circle marker. For more information, see Ring search region.","source":"@site/docs/UserGuide/C19_Measurements/S12_Circle_markersfundamental_and_advanced_characteristics.md","sourceDirName":"UserGuide/C19_Measurements","slug":"/UserGuide/C19_Measurements/S12_Circle_markersfundamental_and_advanced_characteristics","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C19_Measurements/S12_Circle_markersfundamental_and_advanced_characteristics","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D processing and analysis","chapter":"Measurements","section":"Circle_markersfundamental_and_advanced_characteristics","module_tag":"meas","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D processing and analysis / meas / Circle markersfundamental and advanced characteristics"},"sidebar":"userGuideSidebar","previous":{"title":"Stripe markers: advanced characteristics that can be specified","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C19_Measurements/S11_Stripe_markersadvanced_characteristics"},"next":{"title":"Multiple-occurrence marker characteristics","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C19_Measurements/S13_Multiple_occurrence_marker_characteristics"}}');var i=a(74848),t=a(28453);const c={doctype:"UserGuide",part:"2D processing and analysis",chapter:"Measurements",section:"Circle_markersfundamental_and_advanced_characteristics",module_tag:"meas",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D processing and analysis / meas / Circle markersfundamental and advanced characteristics"},n="Circle markers: basic and advanced characteristics that should or can be specified",o={},h=[{value:"Essential characteristics",id:"essential-characteristics",level:2},{value:"Polarity",id:"polarity",level:3},{value:"Maximum association distance of subedges",id:"maximum-association-distance-of-subedges",level:3},{value:"Score characteristics",id:"score-characteristics",level:2},{value:"Radius",id:"radius",level:3}];function d(e){const r={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,t.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(r.header,{children:(0,i.jsx)(r.h1,{id:"circle-markers-basic-and-advanced-characteristics-that-should-or-can-be-specified",children:"Circle markers: basic and advanced characteristics that should or can be specified"})}),"\n",(0,i.jsxs)(r.p,{children:["A circle marker is simply a marker with a closed circular edge. Therefore, edge marker characteristics, as discussed previously in this chapter, generally apply to circle marker characteristics. To establish a circle marker, Aurora Imaging Library finds and extracts subedges using rectangular subregions of a ring search region and applies a circular fit to the subedges. The illustration below shows different possible circles, and how Aurora Imaging Library extracts and fits the subedges according to the ring search region. Note that, although circle markers are closed, the edges that Aurora Imaging Library uses to create them might not be closed; that is, Aurora Imaging Library can establish a circle marker even if part of it is missing. This is due to the fact that only three valid subedges are required to identify a circle marker. For more information, see ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C19_Measurements/S06_Search_region",children:"Ring search region"}),"."]}),"\n",(0,i.jsx)(r.p,{children:(0,i.jsx)(r.em,{children:"[Image: MeasurementHappyCircle.png]"})}),"\n",(0,i.jsx)(r.p,{children:"This section describes basic circle marker characteristics that you should specify for most applications so that the appropriate circle marker is found, as well as some advanced characteristics of a circle marker that you would usually set for advanced applications, when the correct marker is difficult to find. The latter characteristics fall into two categories: those that must be met (essential characteristics) and those for which you can set a range of acceptable scores (score characteristics)."}),"\n",(0,i.jsxs)(r.p,{children:[(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"MmeasSetMarker"})})," sets essential characteristic settings that you should consider both basic (you typically change them) and advanced (you rarely change them), while ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetScore",children:(0,i.jsx)(r.code,{children:"MmeasSetScore"})})," should be considered entirely advanced."]}),"\n",(0,i.jsx)(r.h2,{id:"essential-characteristics",children:"Essential characteristics"}),"\n",(0,i.jsxs)(r.p,{children:["To specify an essential characteristic of a circle marker, use ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"MmeasSetMarker"})}),". Aurora Imaging Library only finds a marker occurrence if it meets all the essential characteristics set in the marker buffer."]}),"\n",(0,i.jsx)(r.h3,{id:"polarity",children:"Polarity"}),"\n",(0,i.jsxs)(r.p,{children:["The polarity of an edge describes whether it is rising (increase in grayscale value) or falling (decrease in grayscale value). For circle markers, the polarity is measured outward, from the circle's center (radially). This is the same direction that ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasFindMarker",children:(0,i.jsx)(r.code,{children:"MmeasFindMarker"})})," uses to find circles."]}),"\n",(0,i.jsx)(r.p,{children:(0,i.jsx)(r.em,{children:"[Image: MeasurementCirclePolarity.png]"})}),"\n",(0,i.jsxs)(r.p,{children:["To specify the polarity, use ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"MmeasSetMarker"})})," with ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_POLARITY"})})," set to ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_ANY"})})," (default), ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_NEGATIVE"})})," (falling edge), or ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_POSITIVE"})})," (rising edge). Polarity is considered a basic characteristic since you must typically consider it for most applications."]}),"\n",(0,i.jsx)(r.h3,{id:"maximum-association-distance-of-subedges",children:"Maximum association distance of subedges"}),"\n",(0,i.jsxs)(r.p,{children:["As previously discussed with edge markers, you can ignore unwanted subedges using ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_MAX_ASSOCIATION_DISTANCE"})}),". Aurora Imaging Library measures the maximum distance radially, along the perimeter of the fitted circle within the rectangular subregions. Subedges that fall outside this range do not affect the marker's fit operation, even if they are in the search region. Therefore, ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetMarker",children:(0,i.jsx)(r.code,{children:"M_MAX_ASSOCIATION_DISTANCE"})})," gives you greater control over restricting the area in which to perform the fit operation, allowing you to better ignore unwanted image elements, such as specks and noise, which could skew your results."]}),"\n",(0,i.jsx)(r.p,{children:(0,i.jsx)(r.em,{children:"[Image: MeasurementMaxAssocCircle.png]"})}),"\n",(0,i.jsx)(r.h2,{id:"score-characteristics",children:"Score characteristics"}),"\n",(0,i.jsxs)(r.p,{children:["To specify a score characteristic of a marker, use ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetScore",children:(0,i.jsx)(r.code,{children:"MmeasSetScore"})}),". As previously discussed, the score characteristics only validate markers that have all the essential characteristics. Of these markers, Aurora Imaging Library chooses the one with the highest edge strength score, by default. This behavior is typically sufficient and you usually don't have to call ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetScore",children:(0,i.jsx)(r.code,{children:"MmeasSetScore"})})," unless you are working on advanced applications."]}),"\n",(0,i.jsxs)(r.p,{children:["Note that although you can specify multiple score characteristics, this can cause results that are difficult to interpret. It is often sufficient, and simpler, to use one score characteristic with which to find the best marker. Since the marker with the highest (best) strength score is found by default, you should therefore typically disable the strength score characteristic before setting another score characteristic (such as, for example, the contrast). For more information about how Aurora Imaging Library calculates scores (as well as how to set a minimum acceptable score), see ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C19_Measurements/S14_Score_characteristics",children:"Score characteristics"}),"."]}),"\n",(0,i.jsx)(r.h3,{id:"radius",children:"Radius"}),"\n",(0,i.jsxs)(r.p,{children:["Radius refers to the distance between a circle's circumference and its center. If the target image has multiple circles with similar radii that share a common position (center), you might have difficulty isolating the circle you want. In such cases, you can find the marker based on a score Aurora Imaging Library establishes according to how well the circle's radius corresponds to the radius specifications set with ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetScore",children:(0,i.jsx)(r.code,{children:"M_RADIUS_SCORE"})}),"."]}),"\n",(0,i.jsx)(r.p,{children:(0,i.jsx)(r.em,{children:"[Image: MeasurementCircleRadius.png]"})}),"\n",(0,i.jsxs)(r.p,{children:["In this example, there are three circles that share the same position (their centers coincide). If you want to find the biggest of these circles, you would typically narrow the ring search region. However, in certain cases, this might cause you to miss smaller circles that you would otherwise want to find if bigger circles were not there. Without having to adjust other characteristics (such as the ring search region), you can use ",(0,i.jsx)(r.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/meas/MmeasSetScore",children:(0,i.jsx)(r.code,{children:"M_RADIUS_SCORE"})})," to calculate a score for the circles within the ring search region, such that the circle with the biggest radius receives that highest score and is therefore found by Aurora Imaging Library."]})]})}function l(e={}){const{wrapper:r}={...(0,t.R)(),...e.components};return r?(0,i.jsx)(r,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,r,a){a.d(r,{R:()=>c,x:()=>n});var s=a(96540);const i={},t=s.createContext(i);function c(e){const r=s.useContext(t);return s.useMemo(function(){return"function"==typeof e?e(r):{...r,...e}},[r,e])}function n(e){let r;return r=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:c(e.components),s.createElement(t.Provider,{value:r},e.children)}}}]);